The following index definition for the
`sample_training.companies` namespace configures MongoDB Search to
automatically index all dynamically indexable fields inside the
objects in the `products` array. It also configures the
`category_code` field to be indexed as the [token](bson-data-types-token) type, which is not included in the default type
set for dynamic mappings, to support MongoDB Search [faceted navigation](fts-facet-ref) queries
against that field.

```csharp
using MongoDB.Bson;
using MongoDB.Driver;

// Replace the connection string with your MongoDB deployment's connection string
var uri = "<connection-string>";

var client = new MongoClient(uri);

var db = client.GetDatabase("sample_training");
var collection = db.GetCollection<BsonDocument>("companies");

// Create the MongoDB Search index definition for the embeddedDocuments field with dynamic mapping
var index =  new CreateSearchIndexModel(
  "default", new BsonDocument
  {
    { "mappings", new BsonDocument
      {
        { "dynamic", true },
        { "fields", new BsonDocument
          {
            { "products", new BsonDocument
              {
                { "dynamic", true },
                { "type", "embeddedDocuments" }
              }
            },
            { "category_code", new BsonDocument
              {
                { "type", "token" }
              }
            }
          }
        }
      }
    }
  });

var result = collection.SearchIndexes.CreateOne(index);
Console.WriteLine($"New index name: {result}");
```

